/**
 * Mock Wallet Context
 * 
 * Simulates MetaMask wallet connection without requiring actual MetaMask.
 * When ready to use real wallet, switch back to WalletContext.js
 */

import React, { createContext, useContext, useState, useEffect } from 'react';

const WalletContext = createContext();

export const useWallet = () => {
  const context = useContext(WalletContext);
  if (!context) {
    throw new Error('useWallet must be used within a WalletProvider');
  }
  return context;
};

export const WalletProvider = ({ children }) => {
  const [account, setAccount] = useState(null);
  const [chainId, setChainId] = useState('0x1'); // Mock Ethereum mainnet
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [ownedNFTs, setOwnedNFTs] = useState([]); // Mock NFTs
  const [userProfile, setUserProfile] = useState({
    displayName: '',
    bio: '',
    avatar: ''
  });

  // Auto-connect on mount (simulates MetaMask auto-connect)
  useEffect(() => {
    const savedAccount = localStorage.getItem('mockWalletAddress');
    if (savedAccount) {
      setAccount(savedAccount);
      setIsConnected(true);
      console.log('🔧 MOCK: Auto-connected wallet:', savedAccount);
    }
  }, []);

  /**
   * Connect wallet (simulates MetaMask connection)
   */
  const connectWallet = async () => {
    setIsConnecting(true);
    
    try {
      // Simulate connection delay
      await new Promise(resolve => setTimeout(resolve, 500));
      
      // Get or create mock address
      let mockAddress = localStorage.getItem('mockWalletAddress');
      
      if (!mockAddress) {
        // Generate random Ethereum-like address
        mockAddress = `0x${Math.random().toString(16).substr(2, 40)}`;
        localStorage.setItem('mockWalletAddress', mockAddress);
      }
      
      setAccount(mockAddress);
      setIsConnected(true);
      
      console.log('✅ MOCK: Wallet connected:', mockAddress);
      console.log('💡 This is a MOCK wallet (no real MetaMask)');
      
      return mockAddress;
    } catch (error) {
      console.error('Failed to connect mock wallet:', error);
      throw error;
    } finally {
      setIsConnecting(false);
    }
  };

  /**
   * Disconnect wallet
   */
  const disconnectWallet = () => {
    setAccount(null);
    setIsConnected(false);
    localStorage.removeItem('mockWalletAddress');
    console.log('🔌 MOCK: Wallet disconnected');
  };

  /**
   * Switch to different mock account (simulates account change)
   */
  const switchAccount = () => {
    const newAddress = `0x${Math.random().toString(16).substr(2, 40)}`;
    localStorage.setItem('mockWalletAddress', newAddress);
    setAccount(newAddress);
    console.log('🔄 MOCK: Switched to new account:', newAddress);
  };

  /**
   * Get balance (mock)
   */
  const getBalance = async () => {
    // Return mock balance
    return '10.5'; // Mock ETH balance
  };

  /**
   * Check if MetaMask is installed (always true in mock mode)
   */
  const isMetaMaskInstalled = () => {
    return true; // Always true in mock mode
  };

  /**
   * Update user profile (mock)
   */
  const updateProfile = (newProfile) => {
    setUserProfile(prev => ({ ...prev, ...newProfile }));
    console.log('🔧 MOCK: Profile updated:', newProfile);
  };

  const value = {
    account,
    walletAddress: account, // Alias for compatibility
    chainId,
    isConnected,
    isConnecting,
    ownedNFTs,
    userProfile,
    connectWallet,
    disconnectWallet,
    switchAccount,
    getBalance,
    isMetaMaskInstalled,
    updateProfile,
    // Mock-specific flags
    isMockMode: true,
    mockMessage: 'Using MOCK wallet (no MetaMask required)'
  };

  return (
    <WalletContext.Provider value={value}>
      {children}
    </WalletContext.Provider>
  );
};
